-- First count how many we're removing
SELECT COUNT(*) as fake_lead_count FROM gigLeads WHERE source = 'gigxo' OR externalId LIKE 'ai-%';

-- Delete all AI-generated fake leads
DELETE FROM gigLeads WHERE source = 'gigxo' OR externalId LIKE 'ai-%';

-- Verify what's left
SELECT source, COUNT(*) as count FROM gigLeads GROUP BY source;

